t.script:
(function() {
    var btnSearch = document.getElementById('btn_search_farmer');
    var searchFarmerId = document.getElementById('search_farmer_id');
    var searchNationalId = document.getElementById('search_national_id');
    var resultsDiv = document.getElementById('farmer_search_results');
    var resultsList = document.getElementById('farmer_results_list');
    var createCard = document.getElementById('create_request_card');
    var formFarmerId = document.getElementById('form_farmer_id');
    var selectedFarmerName = document.getElementById('selected_farmer_name');
    var selectedFarmerMeta = document.getElementById('selected_farmer_meta');
    var selectedFarmerImage = document.getElementById('selected_farmer_image');
    var selectedFarmerImagePlaceholder = document.getElementById('selected_farmer_image_placeholder');
    var btnClear = document.getElementById('btn_clear_farmer');
    var btnSubmitDisabledReason = document.getElementById('btn_submit_disabled_reason');
    var consentForm = document.getElementById('consent_request_form');
    var purposeInput = document.getElementById('purpose');
    var purposeError = document.getElementById('purpose_error');
    var dataFieldInputs = consentForm ? consentForm.querySelectorAll('input[name="allowed_data_field_ids"]') : [];
    var dataFieldsError = document.getElementById('data_fields_error');
    var attachmentInput = consentForm ? consentForm.querySelector('input[name="attachment"]') : null;
    var attachmentError = document.getElementById('attachment_error');
    var cameraDataInput = document.getElementById('camera_capture_data');
    var cameraTakenAtInput = document.getElementById('camera_capture_taken_at');
    var cameraLatitudeInput = document.getElementById('camera_capture_latitude');
    var cameraLongitudeInput = document.getElementById('camera_capture_longitude');
    var cameraAccuracyInput = document.getElementById('camera_capture_accuracy');
    var faceMatchStatusInput = document.getElementById('face_match_status_input');
    var faceMatchDistanceInput = document.getElementById('face_match_distance_input');
    var faceMatchThresholdInput = document.getElementById('face_match_threshold_input');
    var faceMatchCheckedAtInput = document.getElementById('face_match_checked_at_input');
    var faceMatchMessageInput = document.getElementById('face_match_message_input');
    var faydaOtpTransactionIdInput = document.getElementById('fayda_otp_transaction_id_input');
    var cameraInfo = document.getElementById('camera_capture_info');
    var cameraError = document.getElementById('camera_error');
    var cameraPreview = document.getElementById('camera_capture_preview');
    var cameraVideo = document.getElementById('camera_live_preview');
    var cameraCanvas = document.getElementById('camera_canvas');
    var faceMatchStatusText = document.getElementById('face_match_status_text');
    var faceMatchPercentText = document.getElementById('face_match_percent_text');
    var faceMatchReferencePreview = document.getElementById('face_match_reference_preview');
    var faceMatchReferenceEmpty = document.getElementById('face_match_reference_empty');
    var btnOpenCamera = document.getElementById('btn_open_camera');
    var btnTakeCameraPhoto = document.getElementById('btn_take_camera_photo');
    var btnCloseCamera = document.getElementById('btn_close_camera');
    var btnRetakeCameraPhoto = document.getElementById('btn_retake_camera_photo');
    var faydaOtpStatusText = document.getElementById('fayda_otp_status_text');
    var faydaOtpMetaText = document.getElementById('fayda_otp_meta_text');
    var otpVerificationChoiceHint = document.getElementById('otp_verification_choice_hint');
    var faydaOtpCodeInput = document.getElementById('fayda_otp_code');
    var btnRequestFaydaOtp = document.getElementById('btn_request_fayda_otp');
    var btnResendFaydaOtp = document.getElementById('btn_resend_fayda_otp');
    var btnVerifyFaydaOtp = document.getElementById('btn_verify_fayda_otp');
    var verificationSelector = document.getElementById('consent_verification_selector');
    var verificationOtpDetail = document.getElementById('consent_verification_otp_detail');
    var verificationFaceDetail = document.getElementById('consent_verification_face_detail');
    var btnSelectVerificationOtp = document.getElementById('btn_select_verification_otp');
    var btnSelectVerificationFace = document.getElementById('btn_select_verification_face');
    var btnChangeVerificationMethodFromOtp = document.getElementById('btn_change_verification_method_from_otp');
    var btnChangeVerificationMethodFromFace = document.getElementById('btn_change_verification_method_from_face');
    var tableWrap = document.getElementById('consent_table_wrap');
    var tableBody = document.getElementById('consent_request_table_body');
    var tableLoader = document.getElementById('consent_table_loader');
    var tableEnd = document.getElementById('consent_table_end');
    var notificationToggle = document.getElementById('consent_header_notification_toggle');
    var notificationMenu = document.getElementById('consent_header_notification_menu');
    var notificationCount = document.getElementById('consent_header_notification_count');
    var notificationList = document.getElementById('consent_header_notification_list');
    var notificationEmpty = document.getElementById('consent_header_notification_empty');
    var notificationMarkAll = document.getElementById('consent_header_notification_mark_all');
    var maxAttachmentSize = 10 * 1024 * 1024;
    var faceMatchThresholdDefault = 0.45;
    var cameraStream = null;
    var selectedFarmer = null;
    var selectedVerificationMethod = '';
    var faceApiScriptPromise = null;
    var faceApiModelsPromise = null;
    var faceMatchSubmitPending = false;
    var faceMatchActionToken = 0;
    var faydaOtpActionToken = 0;
    var faceMatchState = {
        status: 'not_attempted',
        running: false
    };
    var faydaOtpState = {
        status: 'not_requested',
        running: false,
        transactionId: '',
        maskedMobile: ''
    };

    function closeModalById(modalId) {
        if (!modalId) return;
        var modalEl = document.getElementById(modalId);
        if (!modalEl) return;
        if (window.bootstrap && window.bootstrap.Modal) {
            var modalInstance = window.bootstrap.Modal.getInstance(modalEl);
            if (modalInstance) {
                modalInstance.hide();
                return;
            }
        }
        if (window.jQuery && window.jQuery.fn && window.jQuery.fn.modal) {
            window.jQuery(modalEl).modal('hide');
        }
    }
    var tableScrollTicking = false;
    var errorMessagesByCode = {
        access_denied: 'Access denied. Please contact your administrator.',
        missing_farmer: 'Please search and select a farmer first.',
        invalid_farmer: 'Invalid farmer selected.',
        farmer_not_found: 'Farmer not found.',
        missing_purpose: 'Purpose is required.',
        missing_data_fields: 'No valid data fields selected. Configure partner data fields first.',
        missing_attachment: 'Attachment is required.',
        attachment_too_large: 'Attachment must be 10MB or smaller.',
        camera_too_large: 'Camera photo must be 10MB or smaller.',
        invalid_camera_data: 'Invalid camera image data.',
        invalid_camera_timestamp: 'Invalid camera timestamp.',
        invalid_camera_location: 'Invalid camera capture location.',
        server_error: 'An error occurred while creating the consent request.'
    };

    function toInt(value, fallbackValue) {
        var parsed = parseInt(value, 10);
        return Number.isFinite(parsed) ? parsed : fallbackValue;
    }

    var tableState = {
        total: toInt(tableWrap && tableWrap.getAttribute('data-total'), 0),
        limit: toInt(tableWrap && tableWrap.getAttribute('data-limit'), 10),
        offset: toInt(tableWrap && tableWrap.getAttribute('data-offset'), 0),
        loading: false,
        done: false
    };

    function formatDateForOdoo(dateObj) {
        function pad(v) { return String(v).padStart(2, '0'); }
        return dateObj.getFullYear() + '-' + pad(dateObj.getMonth() + 1) + '-' + pad(dateObj.getDate()) + ' ' +
            pad(dateObj.getHours()) + ':' + pad(dateObj.getMinutes()) + ':' + pad(dateObj.getSeconds());
    }

    function escapeAttr(value) {
        return htmlEscape(value).replace(/"/g, '&quot;');
    }

    function normalizeFaceMatchStatus(status) {
        return String(status || 'not_attempted').toLowerCase().replace(/[^a-z_]/g, '');
    }

    function distanceToMatchPercent(distance) {
        if (!Number.isFinite(distance)) {
            return null;
        }
        return Math.max(0, Math.min(100, (1 - distance) * 100));
    }

    function formatMatchPercent(percentValue) {
        return Number.isFinite(percentValue) ? percentValue.toFixed(1) + '%' : '—';
    }

    function updateFaceMatchPercentText(distance, threshold) {
        if (!faceMatchPercentText) return;
        var safeThreshold = Number.isFinite(threshold) ? threshold : faceMatchThresholdDefault;
        var thresholdPercent = distanceToMatchPercent(safeThreshold);
        if (Number.isFinite(distance)) {
            var matchPercent = distanceToMatchPercent(distance);
            faceMatchPercentText.textContent =
                'Match score: ' + formatMatchPercent(matchPercent) +
                ' | Minimum accepted: ' + formatMatchPercent(thresholdPercent);
        } else {
            faceMatchPercentText.textContent =
                'Minimum accepted: ' + formatMatchPercent(thresholdPercent);
        }
    }

    function setPreviewImage(imgEl, emptyEl, imageUrl) {
        if (imgEl) {
            if (imageUrl) {
                imgEl.src = imageUrl;
                imgEl.classList.remove('d-none');
            } else {
                imgEl.removeAttribute('src');
                imgEl.classList.add('d-none');
            }
        }
        if (emptyEl) {
            emptyEl.classList.toggle('d-none', !!imageUrl);
        }
    }

    function resetFaceMatchFields() {
        if (faceMatchStatusInput) faceMatchStatusInput.value = 'not_attempted';
        if (faceMatchDistanceInput) faceMatchDistanceInput.value = '';
        if (faceMatchThresholdInput) faceMatchThresholdInput.value = '';
        if (faceMatchCheckedAtInput) faceMatchCheckedAtInput.value = '';
        if (faceMatchMessageInput) faceMatchMessageInput.value = '';
        faceMatchState.status = 'not_attempted';
        faceMatchState.running = false;
        updateFaceMatchPercentText(null, faceMatchThresholdDefault);
    }

    function setFaceMatchProcessing(message) {
        faceMatchState.status = 'processing';
        faceMatchState.running = true;
        if (faceMatchStatusText) {
            faceMatchStatusText.className = 'consent_face_match_status is-processing';
            faceMatchStatusText.textContent = message || 'Comparing faces...';
        }
        updateFaceMatchPercentText(null, faceMatchThresholdDefault);
    }

    function setFaceMatchResult(status, message, options) {
        var normalizedStatus = normalizeFaceMatchStatus(status);
        var distance = options && Number.isFinite(options.distance) ? options.distance : null;
        var threshold = options && Number.isFinite(options.threshold) ? options.threshold : faceMatchThresholdDefault;
        var technicalMessage = options && options.technicalMessage ? String(options.technicalMessage) : '';
        faceMatchState.status = normalizedStatus;
        faceMatchState.running = false;
        if (faceMatchStatusInput) faceMatchStatusInput.value = normalizedStatus;
        if (faceMatchDistanceInput) faceMatchDistanceInput.value = distance == null ? '' : String(distance);
        if (faceMatchThresholdInput) faceMatchThresholdInput.value = threshold == null ? '' : String(threshold);
        if (faceMatchCheckedAtInput) {
            faceMatchCheckedAtInput.value = normalizedStatus === 'not_attempted' ? '' : formatDateForOdoo(new Date());
        }
        if (faceMatchMessageInput) {
            faceMatchMessageInput.value = technicalMessage || String(message || '');
        }
        if (faceMatchStatusText) {
            faceMatchStatusText.className = 'consent_face_match_status is-' + normalizedStatus.replace(/_/g, '-');
            faceMatchStatusText.textContent = message || '';
        }
        updateFaceMatchPercentText(distance, threshold);
    }

    function resetFaceMatch(message) {
        resetFaceMatchFields();
        if (faceMatchStatusText) {
            faceMatchStatusText.className = 'consent_face_match_status is-not-attempted';
            faceMatchStatusText.textContent = message || 'Capture a photo to compare it with the selected farmer profile image.';
        }
    }

    function getFaydaOtpUnavailableReason(farmer) {
        if (!farmer) {
            return 'Select a farmer before requesting OTP.';
        }
        if (farmer.otp_available) {
            return '';
        }
        return 'OTP is unavailable for this farmer because the Fayda flow requires a Fayda identifier from the IDs tab. A primary phone can be used as the destination only when that identifier exists.';
    }

    function setOtpVerificationChoiceHint(status, options) {
        if (!otpVerificationChoiceHint) return;
        var normalizedStatus = String(status || 'not_requested').toLowerCase().replace(/[^a-z_]/g, '');
        var opts = options || {};
        var maskedMobile = opts.maskedMobile || '';
        var message = 'Send a code to verify this farmer.';
        var extraClass = '';

        if (!selectedFarmer) {
            message = 'Select a farmer first.';
        } else if (!selectedFarmer.otp_available) {
            message = 'Needs a Fayda ID before OTP can be used.';
            extraClass = 'is-error';
        } else if (normalizedStatus === 'processing') {
            message = 'Working on your OTP request...';
            extraClass = 'is-processing';
        } else if (normalizedStatus === 'requested') {
            message = maskedMobile
                ? 'Code sent to ' + maskedMobile + '.'
                : 'Code sent. Enter it to continue.';
        } else if (normalizedStatus === 'verified') {
            message = 'Verified successfully. You can send another code anytime.';
            extraClass = 'is-success';
        } else if (normalizedStatus === 'failed' || normalizedStatus === 'error') {
            message = 'Verification did not go through. You can try again.';
            extraClass = 'is-error';
        }

        otpVerificationChoiceHint.className = 'consent_verification_choice_text' + (extraClass ? ' ' + extraClass : '');
        otpVerificationChoiceHint.textContent = message;
    }

    function setFaydaOtpButtonsState(inFlight, hasTransaction) {
        var otpAvailable = !!(selectedFarmer && selectedFarmer.otp_available);
        var unavailableReason = getFaydaOtpUnavailableReason(selectedFarmer);
        if (btnRequestFaydaOtp) {
            btnRequestFaydaOtp.disabled = !!inFlight || !otpAvailable;
            btnRequestFaydaOtp.title = !otpAvailable ? unavailableReason : '';
        }
        if (btnResendFaydaOtp) {
            btnResendFaydaOtp.disabled = !!inFlight || !otpAvailable;
            btnResendFaydaOtp.classList.toggle('d-none', !hasTransaction);
            btnResendFaydaOtp.title = !otpAvailable ? unavailableReason : '';
        }
        if (btnVerifyFaydaOtp) {
            btnVerifyFaydaOtp.disabled = !!inFlight || !hasTransaction;
            btnVerifyFaydaOtp.title = !hasTransaction && !otpAvailable ? unavailableReason : '';
        }
        if (faydaOtpCodeInput) faydaOtpCodeInput.disabled = !!inFlight || !hasTransaction;
    }

    function setFaydaOtpStatus(status, message, options) {
        var normalizedStatus = String(status || 'not_requested').toLowerCase().replace(/[^a-z_]/g, '');
        var opts = options || {};
        var transactionId = opts.transactionId || '';
        var maskedMobile = opts.maskedMobile || '';
        var identifierType = opts.identifierType || '';
        var identifierSource = opts.identifierSource || '';
        var verifiedAt = opts.verifiedAt || '';
        faydaOtpState.status = normalizedStatus;
        faydaOtpState.running = normalizedStatus === 'processing';
        faydaOtpState.transactionId = transactionId;
        faydaOtpState.maskedMobile = maskedMobile;
        if (faydaOtpTransactionIdInput) {
            faydaOtpTransactionIdInput.value = transactionId;
        }
        if (faydaOtpStatusText) {
            faydaOtpStatusText.className = 'consent_otp_status is-' + normalizedStatus.replace(/_/g, '-');
            faydaOtpStatusText.textContent = message || '';
        }
        if (faydaOtpMetaText) {
            var metaParts = [];
            if (maskedMobile) metaParts.push('Masked mobile: ' + maskedMobile);
            if (identifierType) metaParts.push('Identifier type: ' + identifierType);
            if (identifierSource) metaParts.push('Source: ' + identifierSource);
            if (verifiedAt) metaParts.push('Verified at: ' + verifiedAt);
            if (!metaParts.length) {
                metaParts.push('A verified OTP or a successful face match will auto-approve this request on submit.');
            }
            faydaOtpMetaText.textContent = metaParts.join(' | ');
        }
        setOtpVerificationChoiceHint(normalizedStatus, { maskedMobile: maskedMobile });
        setFaydaOtpButtonsState(normalizedStatus === 'processing', !!transactionId);
    }

    function resetFaydaOtp(message) {
        faydaOtpActionToken += 1;
        faydaOtpState.status = 'not_requested';
        faydaOtpState.running = false;
        faydaOtpState.transactionId = '';
        faydaOtpState.maskedMobile = '';
        if (faydaOtpTransactionIdInput) faydaOtpTransactionIdInput.value = '';
        if (faydaOtpCodeInput) {
            faydaOtpCodeInput.value = '';
            faydaOtpCodeInput.disabled = true;
        }
        if (faydaOtpStatusText) {
            faydaOtpStatusText.className = 'consent_otp_status is-not-requested';
            faydaOtpStatusText.textContent = message || 'Request OTP to verify the selected farmer.';
        }
        if (faydaOtpMetaText) {
            faydaOtpMetaText.textContent = 'A verified OTP or a successful face match will auto-approve this request on submit.';
        }
        setOtpVerificationChoiceHint('not_requested');
        setFaydaOtpButtonsState(false, false);
    }

    function getDefaultFaceMatchMessage(farmer, isRetake) {
        if (farmer && farmer.profile_image_url) {
            return isRetake
                ? 'Retake the photo to compare it with the selected farmer profile image.'
                : 'Capture a photo to compare it with the selected farmer profile image.';
        }
        return 'Selected farmer has no profile image. The request can still be submitted, but it will remain pending.';
    }

    function getDefaultFaydaOtpMessage(farmer) {
        return farmer && farmer.otp_available
            ? 'Request OTP to verify the selected farmer.'
            : getFaydaOtpUnavailableReason(farmer);
    }

    function clearCameraCapture() {
        faceMatchActionToken += 1;
        stopCameraStream();
        if (cameraDataInput) cameraDataInput.value = '';
        if (cameraTakenAtInput) cameraTakenAtInput.value = '';
        clearCameraLocation();
        if (cameraPreview) {
            cameraPreview.src = '';
            cameraPreview.classList.add('d-none');
        }
        if (cameraVideo) {
            cameraVideo.classList.add('d-none');
        }
        if (cameraInfo) {
            cameraInfo.textContent = '';
            cameraInfo.classList.add('d-none');
        }
        setCameraError('');
        showCameraButtons(false, false);
    }

    function setVerificationMethod(method) {
        var normalizedMethod = method === 'otp' || method === 'face' ? method : '';
        var previousMethod = selectedVerificationMethod;

        if (previousMethod === 'face' && normalizedMethod !== 'face') {
            clearCameraCapture();
            resetFaceMatch(getDefaultFaceMatchMessage(selectedFarmer, false));
        }
        if (previousMethod === 'otp' && normalizedMethod !== 'otp') {
            resetFaydaOtp(getDefaultFaydaOtpMessage(selectedFarmer));
        }

        selectedVerificationMethod = normalizedMethod;

        if (btnSelectVerificationOtp) {
            btnSelectVerificationOtp.classList.toggle('is-selected', normalizedMethod === 'otp');
        }
        if (btnSelectVerificationFace) {
            btnSelectVerificationFace.classList.toggle('is-selected', normalizedMethod === 'face');
        }

        if (normalizedMethod === 'otp') {
            var modalOtp = document.getElementById('modal_verification_otp');
            if (modalOtp) {
                if (window.bootstrap && window.bootstrap.Modal) {
                    window.bootstrap.Modal.getOrCreateInstance(modalOtp).show();
                } else if (window.jQuery) {
                    window.jQuery('#modal_verification_otp').modal('show');
                }
            }
        } else if (normalizedMethod === 'face') {
            var modalFace = document.getElementById('modal_verification_face');
            if (modalFace) {
                if (window.bootstrap && window.bootstrap.Modal) {
                    window.bootstrap.Modal.getOrCreateInstance(modalFace).show();
                } else if (window.jQuery) {
                    window.jQuery('#modal_verification_face').modal('show');
                }
            }
        }
    }

    function callJsonRoute(url, params) {
        return new Promise(function(resolve, reject) {
            var req = new XMLHttpRequest();
            req.open('POST', url);
            req.setRequestHeader('Content-Type', 'application/json');
            req.setRequestHeader('Accept', 'application/json');
            req.onload = function() {
                var raw = {};
                try {
                    raw = JSON.parse(req.responseText || '{}');
                } catch (e) {
                    reject(new Error('Server returned an invalid response.'));
                    return;
                }
                var res = raw.result != null ? raw.result : raw;
                if (res && res.success) {
                    resolve(res);
                    return;
                }
                reject(new Error((res && res.message) || 'Request failed.'));
            };
            req.onerror = function() {
                reject(new Error('Network error while contacting the server.'));
            };
            req.send(JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: params || {},
                id: Date.now()
            }));
        });
    }

    function buildFarmerMeta(farmer) {
        if (!farmer) {
            return 'Search and select an approved farmer.';
        }
        var regIds = Array.isArray(farmer.reg_ids) ? farmer.reg_ids.filter(Boolean) : [];
        var parts = ['Farmer ID: ' + (farmer.farmer_id || '—')];
        if (regIds.length) {
            parts.push('IDs: ' + regIds.join(', '));
        }
        if (farmer.otp_available) {
            parts.push('OTP: ' + (farmer.otp_identifier_type || 'ID') + ' ready');
        } else {
            parts.push('OTP unavailable');
        }
        if (!farmer.profile_image_url) {
            parts.push('No profile image available');
        }
        return parts.join(' | ');
    }

    function applySelectedFarmer(farmer) {
        selectedFarmer = farmer || null;
        if (formFarmerId) {
            formFarmerId.value = farmer && farmer.id ? String(farmer.id) : '';
        }
        if (selectedFarmerName) {
            selectedFarmerName.textContent = farmer && farmer.name ? farmer.name : '—';
        }
        if (selectedFarmerMeta) {
            selectedFarmerMeta.textContent = buildFarmerMeta(farmer);
        }
        setPreviewImage(
            selectedFarmerImage,
            selectedFarmerImagePlaceholder,
            farmer && farmer.profile_image_url ? farmer.profile_image_url : ''
        );
        setPreviewImage(
            faceMatchReferencePreview,
            faceMatchReferenceEmpty,
            farmer && farmer.profile_image_url ? farmer.profile_image_url : ''
        );
        createCard.classList.toggle('d-none', !farmer);
        clearCameraCapture();
        setVerificationMethod('');
        resetFaceMatch(getDefaultFaceMatchMessage(farmer, false));
        resetFaydaOtp(getDefaultFaydaOtpMessage(farmer));
    }

    function ensureFaceApiLibrary() {
        if (window.faceapi) {
            return Promise.resolve(window.faceapi);
        }
        if (faceApiScriptPromise) {
            return faceApiScriptPromise;
        }
        faceApiScriptPromise = new Promise(function(resolve, reject) {
            var script = document.createElement('script');
            script.src = '/g2p_ati_consent_mgt/static/src/lib/face-api/face-api.js';
            script.async = true;
            script.onload = function() {
                if (window.faceapi) {
                    resolve(window.faceapi);
                } else {
                    reject(new Error('face-api library loaded without exposing faceapi.'));
                }
            };
            script.onerror = function() {
                reject(new Error('Unable to load face-api library.'));
            };
            document.head.appendChild(script);
        }).catch(function(error) {
            faceApiScriptPromise = null;
            throw error;
        });
        return faceApiScriptPromise;
    }

    function ensureFaceApiModels() {
        if (faceApiModelsPromise) {
            return faceApiModelsPromise;
        }
        faceApiModelsPromise = ensureFaceApiLibrary().then(function(faceapi) {
            var modelBaseUrl = '/g2p_ati_consent_mgt/static/src/lib/face-api/model';
            return Promise.all([
                faceapi.nets.tinyFaceDetector.loadFromUri(modelBaseUrl),
                faceapi.nets.faceLandmark68Net.loadFromUri(modelBaseUrl),
                faceapi.nets.faceRecognitionNet.loadFromUri(modelBaseUrl)
            ]).then(function() {
                return faceapi;
            });
        }).catch(function(error) {
            faceApiModelsPromise = null;
            throw error;
        });
        return faceApiModelsPromise;
    }

    function loadImageForFaceMatch(imageUrl) {
        return new Promise(function(resolve, reject) {
            if (!imageUrl) {
                reject(new Error('Missing image source.'));
                return;
            }
            var img = new Image();
            if (!/^data:/i.test(imageUrl)) {
                img.crossOrigin = 'anonymous';
            }
            img.onload = function() { resolve(img); };
            img.onerror = function() { reject(new Error('Unable to load image for face matching.')); };
            img.src = imageUrl;
        });
    }

    function detectFaceDescriptor(imageUrl) {
        return ensureFaceApiModels().then(function(faceapi) {
            return loadImageForFaceMatch(imageUrl).then(function(img) {
                return faceapi
                    .detectSingleFace(img, new faceapi.TinyFaceDetectorOptions({ inputSize: 416, scoreThreshold: 0.5 }))
                    .withFaceLandmarks()
                    .withFaceDescriptor();
            });
        });
    }

    function runFaceMatch() {
        var actionToken = ++faceMatchActionToken;
        if (!selectedFarmer) {
            resetFaceMatch('Select a farmer before capturing a photo.');
            return Promise.resolve(false);
        }
        if (!cameraDataInput || !cameraDataInput.value) {
            resetFaceMatch(
                selectedFarmer.profile_image_url
                    ? 'Capture a photo to compare it with the selected farmer profile image.'
                    : 'Selected farmer has no profile image. The request can still be submitted, but it will remain pending.'
            );
            return Promise.resolve(false);
        }
        if (!selectedFarmer.profile_image_url) {
            setFaceMatchResult(
                'no_reference',
                'Selected farmer has no profile image. The request can still be submitted, but it will remain pending.',
                { threshold: faceMatchThresholdDefault }
            );
            return Promise.resolve(false);
        }

        setFaceMatchProcessing('Comparing captured photo with farmer profile image...');
        return Promise.all([
            detectFaceDescriptor(selectedFarmer.profile_image_url),
            detectFaceDescriptor(cameraDataInput.value)
        ]).then(function(results) {
            if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                return false;
            }
            var referenceFace = results[0];
            var capturedFace = results[1];
            if (!referenceFace || !capturedFace) {
                setFaceMatchResult(
                    'no_face_detected',
                    !referenceFace
                        ? 'No face was detected in the farmer profile image. The request will remain pending.'
                        : 'No face was detected in the captured photo. Retake the photo for auto-approval.',
                    { threshold: faceMatchThresholdDefault }
                );
                return false;
            }
            var distance = window.faceapi.euclideanDistance(referenceFace.descriptor, capturedFace.descriptor);
            var matchPercent = distanceToMatchPercent(distance);
            var acceptedPercent = distanceToMatchPercent(faceMatchThresholdDefault);
            var matched = distance <= faceMatchThresholdDefault;
            setFaceMatchResult(
                matched ? 'matched' : 'not_matched',
                matched
                    ? 'Face matched at ' + formatMatchPercent(matchPercent) + '. The request will be automatically approved on submit.'
                    : 'Face match score is ' + formatMatchPercent(matchPercent) + '. Minimum accepted is ' + formatMatchPercent(acceptedPercent) + ', so the request will remain pending.',
                {
                    distance: distance,
                    threshold: faceMatchThresholdDefault,
                    technicalMessage:
                        'Distance=' + distance.toFixed(4) +
                        ', Threshold=' + faceMatchThresholdDefault.toFixed(4) +
                        ', MatchPercent=' + formatMatchPercent(matchPercent) +
                        ', AcceptedPercent=' + formatMatchPercent(acceptedPercent)
                }
            );
            return matched;
        }).catch(function(error) {
            if (actionToken !== faceMatchActionToken || selectedVerificationMethod !== 'face') {
                return false;
            }
            console.error('Consent portal face match failed.', error);
            setFaceMatchResult(
                'error',
                'Face match could not be completed. The request can still be submitted and will remain pending.',
                {
                    threshold: faceMatchThresholdDefault,
                    technicalMessage: error && error.message ? error.message : 'Unknown face match error'
                }
            );
            return false;
        });
    }

    function requestFaydaOtp() {
        var actionToken = ++faydaOtpActionToken;
        if (!selectedFarmer || !selectedFarmer.id) {
            setFaydaOtpStatus('error', 'Select a farmer before requesting OTP.');
            return Promise.resolve(false);
        }
        if (!selectedFarmer.otp_available) {
            setFaydaOtpStatus('error', 'Selected farmer has no Fayda OTP identifier.');
            return Promise.resolve(false);
        }
        setFaydaOtpStatus(
            'processing',
            'Requesting OTP from Fayda...',
            {
                identifierType: selectedFarmer.otp_identifier_type || '',
                identifierSource: selectedFarmer.otp_identifier_source || ''
            }
        );
        return callJsonRoute('/consent/fayda/request_otp', {
            farmer_id: selectedFarmer.id
        }).then(function(res) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            var data = res.data || {};
            setFaydaOtpStatus(
                'requested',
                res.message || 'OTP sent successfully.',
                {
                    transactionId: data.transaction_id || '',
                    maskedMobile: data.masked_mobile || '',
                    identifierType: data.identifier_type || selectedFarmer.otp_identifier_type || '',
                    identifierSource: data.identifier_source || selectedFarmer.otp_identifier_source || ''
                }
            );
            if (faydaOtpCodeInput) {
                faydaOtpCodeInput.focus();
            }
            return true;
        }).catch(function(error) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            setFaydaOtpStatus(
                'error',
                error && error.message ? error.message : 'Unable to request OTP.',
                {
                    identifierType: selectedFarmer.otp_identifier_type || '',
                    identifierSource: selectedFarmer.otp_identifier_source || ''
                }
            );
            return false;
        });
    }

    function verifyFaydaOtp() {
        var actionToken = ++faydaOtpActionToken;
        if (!selectedFarmer || !selectedFarmer.id) {
            setFaydaOtpStatus('error', 'Select a farmer before verifying OTP.');
            return Promise.resolve(false);
        }
        if (!faydaOtpState.transactionId) {
            setFaydaOtpStatus('error', 'Request OTP first.');
            return Promise.resolve(false);
        }
        var otpCode = faydaOtpCodeInput ? (faydaOtpCodeInput.value || '').trim() : '';
        if (!otpCode) {
            setFaydaOtpStatus('error', 'Enter the OTP code.');
            return Promise.resolve(false);
        }
        setFaydaOtpStatus(
            'processing',
            'Verifying OTP with Fayda...',
            {
                transactionId: faydaOtpState.transactionId,
                maskedMobile: faydaOtpState.maskedMobile,
                identifierType: selectedFarmer.otp_identifier_type || '',
                identifierSource: selectedFarmer.otp_identifier_source || ''
            }
        );
        return callJsonRoute('/consent/fayda/verify_otp', {
            farmer_id: selectedFarmer.id,
            transaction_id: faydaOtpState.transactionId,
            otp_code: otpCode
        }).then(function(res) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            var data = res.data || {};
            setFaydaOtpStatus(
                'verified',
                res.message || 'Fayda OTP verified successfully.',
                {
                    transactionId: data.transaction_id || faydaOtpState.transactionId,
                    maskedMobile: data.masked_mobile || faydaOtpState.maskedMobile,
                    identifierType: selectedFarmer.otp_identifier_type || '',
                    identifierSource: selectedFarmer.otp_identifier_source || '',
                    verifiedAt: data.verified_at || ''
                }
            );
            closeModalById('modal_verification_otp');
            window.setTimeout(function() {
                showServiceProviderModal('Fayda OTP verified successfully. You can now submit the request.', false);
            }, 250);
            return true;
        }).catch(function(error) {
            if (actionToken !== faydaOtpActionToken || selectedVerificationMethod !== 'otp') {
                return false;
            }
            setFaydaOtpStatus(
                'failed',
                error && error.message ? error.message : 'OTP verification failed.',
                {
                    transactionId: faydaOtpState.transactionId,
                    maskedMobile: faydaOtpState.maskedMobile,
                    identifierType: selectedFarmer.otp_identifier_type || '',
                    identifierSource: selectedFarmer.otp_identifier_source || ''
                }
            );
            return false;
        });
    }

