    }
    if (faydaOtpCodeInput) {
        faydaOtpCodeInput.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') {
                e.preventDefault();
                verifyFaydaOtp();
            }
        });
    }
    if (btnClear) {
        btnClear.addEventListener('click', function() {
            applySelectedFarmer(null);
        });
    }
    if (btnSubmitDisabledReason) {
        btnSubmitDisabledReason.addEventListener('click', function() {
            var msg = 'No data fields are configured for your consent partner. Contact admin.';
            setDataFieldsError(msg);
            showServiceProviderModal(msg, true);
            console.warn('Consent portal submit blocked on client: no partner data fields configured.');
        });
    }
    if (attachmentInput) {
        attachmentInput.addEventListener('change', function() {
            setAttachmentError('');
            var file = (this.files && this.files.length) ? this.files[0] : null;
            if (file && file.size > maxAttachmentSize) {
                setAttachmentError('Attachment must be 10MB or smaller.');
            }
        });
    }
    if (purposeInput) {
        purposeInput.addEventListener('input', function() {
            if ((this.value || '').trim()) {
                setPurposeError('');
            }
        });
    }
    if (dataFieldInputs && dataFieldInputs.length) {
        for (var i = 0; i < dataFieldInputs.length; i++) {
            dataFieldInputs[i].addEventListener('change', function() {
                if (hasSelectedDataField()) {
                    setDataFieldsError('');
                }
            });
        }
    }
    if (btnOpenCamera) {
        btnOpenCamera.addEventListener('click', function() {
            setCameraError('');
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                setCameraError('Camera is not supported on this device/browser.');
                return;
            }
            navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } })
                .then(function(stream) {
                    cameraStream = stream;
                    if (cameraVideo) {
                        cameraVideo.srcObject = stream;
                        cameraVideo.classList.remove('d-none');
                    }
                    showCameraButtons(true, false);
                })
                .catch(function() {
                    setCameraError('Unable to access camera. Please allow camera permission.');
                });
        });
    }

    if (btnCloseCamera) {
        btnCloseCamera.addEventListener('click', function() {
            stopCameraStream();
            if (cameraVideo) cameraVideo.classList.add('d-none');
            showCameraButtons(false, !!(cameraDataInput && cameraDataInput.value));
        });
    }

    if (btnTakeCameraPhoto) {
        btnTakeCameraPhoto.addEventListener('click', function() {
            setCameraError('');
            if (!cameraVideo || !cameraCanvas || !cameraStream) {
                setCameraError('Open camera first.');
                return;
            }
            var width = cameraVideo.videoWidth || 0;
            var height = cameraVideo.videoHeight || 0;
            if (!width || !height) {
                setCameraError('Camera preview not ready. Try again.');
                return;
            }
            cameraCanvas.width = width;
            cameraCanvas.height = height;
            var ctx = cameraCanvas.getContext('2d');
            ctx.drawImage(cameraVideo, 0, 0, width, height);
            var dataUrl = cameraCanvas.toDataURL('image/jpeg', 0.9);
            var base64Part = dataUrl.split(',')[1] || '';
            var approxBytes = Math.floor((base64Part.length * 3) / 4);
            if (approxBytes > maxAttachmentSize) {
                setCameraError('Camera photo must be 10MB or smaller.');
                return;
            }
            if (cameraDataInput) cameraDataInput.value = dataUrl;
            var capturedAt = new Date();
            if (cameraTakenAtInput) cameraTakenAtInput.value = formatDateForOdoo(capturedAt);
            clearCameraLocation();
            if (cameraInfo) {
                cameraInfo.textContent = 'Captured at: ' + capturedAt.toLocaleString() + ' (getting location...)';
                cameraInfo.classList.remove('d-none');
            }
            getCameraLocation(function(hasLocation) {
                if (!cameraInfo) return;
                var message = 'Captured at: ' + capturedAt.toLocaleString();
                if (hasLocation && cameraLatitudeInput && cameraLongitudeInput) {
                    var lat = Number(cameraLatitudeInput.value || 0).toFixed(6);
                    var lon = Number(cameraLongitudeInput.value || 0).toFixed(6);
                    message += ' | Location: ' + lat + ', ' + lon;
                    if (cameraAccuracyInput && cameraAccuracyInput.value) {
                        var accuracy = Number(cameraAccuracyInput.value || 0).toFixed(1);
                        message += ' (± ' + accuracy + ' m)';
                    }
                } else {
                    message += ' | Location unavailable';
                }
                cameraInfo.textContent = message;
                cameraInfo.classList.remove('d-none');
            });
            if (cameraPreview) {
                cameraPreview.src = dataUrl;
                cameraPreview.classList.remove('d-none');
            }
            stopCameraStream();
            if (cameraVideo) cameraVideo.classList.add('d-none');
            showCameraButtons(false, true);
            runFaceMatch();
        });
    }

    if (btnRetakeCameraPhoto) {
        btnRetakeCameraPhoto.addEventListener('click', function() {
            clearCameraCapture();
            resetFaceMatch(getDefaultFaceMatchMessage(selectedFarmer, true));
        });
    }
    if (consentForm) {
        consentForm.addEventListener('submit', function(e) {
            var hasError = false;
            var firstErrorMessage = '';
            var shouldAttemptFaceMatch = !!(
                selectedVerificationMethod === 'face' &&
                selectedFarmer &&
                selectedFarmer.profile_image_url &&
                cameraDataInput &&
                cameraDataInput.value &&
                faydaOtpState.status !== 'verified'
            );
            setPurposeError('');
            setDataFieldsError('');
            setAttachmentError('');
            setCameraError('');

            if (!purposeInput || !(purposeInput.value || '').trim()) {
                setPurposeError('Purpose is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Purpose is required.';
            }
            if (dataFieldInputs && dataFieldInputs.length && !hasSelectedDataField()) {
                setDataFieldsError('Select at least one data field.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Select at least one data field.';
            }
            if (!attachmentInput) {
                setAttachmentError('Attachment is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment is required.';
            }
            var file = attachmentInput && attachmentInput.files && attachmentInput.files.length ? attachmentInput.files[0] : null;
            if (!file) {
                setAttachmentError('Attachment is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment is required.';
            } else if (file.size > maxAttachmentSize) {
                setAttachmentError('Attachment must be 10MB or smaller.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment must be 10MB or smaller.';
            }

            if (cameraDataInput && cameraDataInput.value) {
                var rawBase64 = cameraDataInput.value.split(',')[1] || '';
                var approxBytes = Math.floor((rawBase64.length * 3) / 4);
                if (approxBytes > maxAttachmentSize) {
                    setCameraError('Camera photo must be 10MB or smaller.');
                    hasError = true;
                    if (!firstErrorMessage) firstErrorMessage = 'Camera photo must be 10MB or smaller.';
                }
            }

            if (faceMatchState.running) {
                setCameraError('Face match is still running. Please wait a moment.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Face match is still running. Please wait a moment.';
            }
            if (faydaOtpState.running) {
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'OTP verification is still running. Please wait a moment.';
            }

            if (hasError) {
                console.warn('Consent portal submit blocked on client validation.', {
                    hasPurpose: !!(purposeInput && (purposeInput.value || '').trim()),
                    hasSelectedDataField: hasSelectedDataField(),
                    hasAttachment: !!(attachmentInput && attachmentInput.files && attachmentInput.files.length),
                    dataFieldInputsCount: dataFieldInputs ? dataFieldInputs.length : 0
                });
                showServiceProviderModal(firstErrorMessage || 'Please fix form validation errors.', true);
                e.preventDefault();
            } else if (shouldAttemptFaceMatch && !faceMatchSubmitPending && faceMatchStatusInput && faceMatchStatusInput.value === 'not_attempted') {
                e.preventDefault();
                faceMatchSubmitPending = true;
                setCameraError('');
                setFaceMatchProcessing('Comparing faces before submit...');
                runFaceMatch().finally(function() {
                    faceMatchSubmitPending = false;
                    if (typeof consentForm.requestSubmit === 'function') {
                        consentForm.requestSubmit();
                    } else {
                        consentForm.submit();
                    }
                });
            } else {
                console.info('Consent portal submit passed client validation. Submitting form.');
            }
        });
    }

    setVerificationMethod('');
    resetFaceMatch(getDefaultFaceMatchMessage(null, false));
    resetFaydaOtp(getDefaultFaydaOtpMessage(null));

    (function showServerErrorPopup() {
        var errorCode = '';
        try {
            errorCode = new URLSearchParams(window.location.search).get('error') || '';
        } catch (e) {
            errorCode = '';
        }
        if (!errorCode) return;
        var message = errorMessagesByCode[errorCode];
        if (!message) return;
        showServiceProviderModal(message, true);
    })();
    window.addEventListener('beforeunload', function() {
        stopCameraStream();
    });
})();
